              d="M540.75,288.71c0.04,3.32-2.62,5.93-6.09,5.97c-2.93,0.04-5.05-1.85-5.09-4.53c-0.04-2.84,3.1-6.01,5.99-6.06 C538.66,284.04,540.71,285.86,540.75,288.71z"
